import { useEffect, useState } from "react";
//import swal from 'sweetalert';
import React from 'react';
import Modalcontrol from "./modal";
import {  Link} from "react-router-dom";
import Userlist from "./userlist";


const Header = () =>{
    let [userlist, picklist] = useState([]);

    useEffect(()=>{
        <Userlist/>
    },[1])

    const logout = () =>{
        localStorage.clear();
        window.location.href="http://localhost:3000/#/"; // it will go to dashboard
        window.location.reload(); // it will reload the app. js(window) file
        
        //other method - window.location.href="http://localhost:3000/#/";
    }

    return (   
          <section className="bg-light p-3">
            <div className="container-fluid">
                <div className="row">
                    <div className="col-lg-6">
                        <h2> User Management System</h2> 
                    </div>

                    <div className="col-lg-6 text-end">
                    <Link className="btn btn-primary m-1" to="/adduser"> <i className='fa fa-plus'></i>  Add User </Link>
                        <div className="btn btn-danger" onClick={logout}><small className="text-white"> { localStorage.getItem("fullname") } </small>
                        <b  className="text-white  "> Logout </b></div>
                    </div>
                </div>
            </div>
        </section>
    
    );
    }

export default Header;
